',{id:"county_water_system_violations",title:"Safe drinking water violations by county 2024 - the infrastructure crisis hiding under your tap",sub:"Over 7 million Americans received water from systems with health-based violations in 2023. Jackson MS: 30+ consecutive years of federal violations. The water violation geography tracks infrastructure age, poverty, and municipal fiscal stress with near-perfect fidelity.",type:"MAP",geo:"us_county",fmt:"County choropleth",tbl:"EPA SDWIS Safe Drinking Water Information System violations by system (public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["pct_bridges_poor","median_household_income"],join:["rural_population_pct","pct_on_snap","per_capita_health_spending"],sc:{emotional:9,relatability:8,surprise:8,tension:8,visual:7,data_ready:9,originality:6},vs:80,tags:"safe drinking water violations county 2024 7 million health-based Jackson MS 30 years federal infrastructure age poverty municipal fiscal EPA SDWIS"}',
',{id:"us_power_grid_outage_frequency_map",title:"Power outage frequency by state 2019-2024 - which states go dark the most",sub:"Louisiana: 429 minutes average customer interruption per year - highest in the US. West Virginia: 389 minutes. Texas: 312 minutes (post-Uri reforms did not fix the grid). Vermont: 41 minutes - best in the nation. The outage geography follows grid age, storm exposure, and utility investment rates.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"EIA Electric Power Annual reliability data by state 2019-2024 (public)",section:"Energy",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","EIA State Energy Data System: production + consumption by state (eia.gov - free API)"],vars:["energy_consumption_per_capita","renewable_energy_share"],join:["median_household_income","rep_pct","rural_population_pct"],sc:{emotional:8,relatability:8,surprise:7,tension:7,visual:7,data_ready:9,originality:5},vs:74,tags:"power outage frequency state 2019 2024 Louisiana 429 minutes West Virginia 389 Texas 312 Vermont 41 best grid age storm exposure utility investment EIA Electric Power Annual"}',
',{id:"us_dam_safety_risk_by_state",title:"High-hazard dams in poor condition by state - the flood risk nobody talks about",sub:"There are 2,303 high-hazard dams in poor or unsatisfactory condition in the US. If any of these fail, downstream communities face fatalities. Texas has 227 such dams - the most of any state. The dam safety crisis is an invisible infrastructure risk with a clear geographic pattern.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"ASDSO State Dam Safety Programs + FEMA National Dam Safety Program (public)",section:"Geography",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["total_dams","pct_bridges_poor"],join:["state_local_debt_per_capita","median_household_income","rural_population_pct"],sc:{emotional:8,relatability:5,surprise:9,tension:7,visual:8,data_ready:8,originality:8},vs:75,tags:"high-hazard dams poor condition state 2303 Texas 227 most flood fatalities downstream infrastructure invisible risk ASDSO FEMA National Dam Safety Program"}',
',{id:"lead_pipe_inventory_by_city",title:"Lead service line count by city - the Flint problem that exists everywhere",sub:"Chicago: 400,000 lead service lines - the most of any US city. Cleveland: 85,000. Detroit: 80,000. EPA mandated a national inventory in 2024. Lead pipes are concentrated in Midwest cities built in the 1900s-1940s. Flint was not an exception - it was a warning.",type:"MAP",geo:"us_city",fmt:"City map",tbl:"EPA Lead and Copper Rule revised service line inventory 2024 (public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","CDC WONDER: mortality + disease rates by county/state (wonder.cdc.gov - free)"],vars:["pct_bridges_poor","per_capita_health_spending"],join:["median_household_income","pct_on_snap","rural_population_pct"],sc:{emotional:9,relatability:7,surprise:8,tension:8,visual:7,data_ready:8,originality:7},vs:80,tags:"lead service lines city Chicago 400K Cleveland 85K Detroit 80K Flint warning Midwest 1900s 1940s EPA inventory 2024 Lead Copper Rule exception everywhere"}',
',{id:"xref_infrastructure_spending_vs_gdp_country",title:"Infrastructure spending as percent of GDP by country vs. GDP growth - does it pay off?",sub:"China: 8.2% of GDP in infrastructure annually 2010-2024. USA: 2.3%. Germany: 2.8%. The countries with highest infrastructure investment show 0.7 percentage points higher GDP growth per year on average. The US infrastructure gap compounds at 0.4% of GDP per year in foregone productivity.",type:"XREF",geo:"worldwide",fmt:"Scatter plot",tbl:"McKinsey Global Infrastructure Initiative + World Bank infrastructure data (public)",section:"Transportation",ext:["World Bank Open Data: GDP, population, income by country (data.worldbank.org - free API)"],vars:["pct_bridges_poor","total_dams"],join:["rd_pct_gdp","trade_balance_goods","net_migration_rate"],sc:{emotional:6,relatability:5,surprise:7,tension:5,visual:4,data_ready:7,originality:6},vs:57,tags:"infrastructure spending GDP country China 8.2% USA 2.3% Germany 2.8% 0.7 points higher growth gap 0.4% foregone productivity McKinsey World Bank compounds"}',
',{id:"freight_rail_network_utilization_map",title:"Freight rail utilization and speed by corridor 2024 - the slow veins of the American economy",sub:"The US has the largest freight rail network in the world: 140,000 route miles. Average freight train speed: 24 mph - half the speed of 1980. The slowdown is caused by longer trains (up to 3 miles), single-track chokepoints, and deferred maintenance. The slowest corridors are in the Gulf Coast and Midwest.",type:"MAP",geo:"us_national",fmt:"Special map",tbl:"AAR railroad data + FRA freight performance metrics (public annual)",section:"Transportation",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)"],vars:["waterway_freight_tons","port_total_tons"],join:["manufacturing_employment_trend","energy_consumption_per_capita","coal_production_index"],sc:{emotional:5,relatability:5,surprise:7,tension:4,visual:9,data_ready:7,originality:7},vs:60,tags:"freight rail utilization speed corridor 2024 140000 route miles 24 mph half 1980 longer trains 3 miles single-track chokepoints Gulf Coast Midwest AAR FRA performance"}',
',{id:"county_sewage_overflow_events_map",title:"Combined sewer overflow events by city/county 2023 - sewage in the streets and rivers",sub:"Combined sewer overflows released 850 billion gallons of raw sewage into US waterways in 2023. The CSO geography is entirely an infrastructure age map - it traces cities built before 1950 with combined storm/sewer systems. The Great Lakes region is the epicenter.",type:"MAP",geo:"us_county",fmt:"County choropleth",tbl:"EPA ECHO database CSO events by permit holder 2023 (public)",section:"Geography",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["pct_bridges_poor","rural_population_pct"],join:["state_local_debt_per_capita","median_household_income","population_pct_change"],sc:{emotional:8,relatability:6,surprise:8,tension:6,visual:7,data_ready:8,originality:7},vs:72,tags:"combined sewer overflow CSO events county 2023 850 billion gallons raw sewage waterways infrastructure age before 1950 Great Lakes epicenter EPA ECHO permit holder"}',
',{id:"us_airport_on_time_performance_by_hub",title:"On-time performance by airport hub 2024 - which airports reliably fail you",sub:"San Francisco SFO: 71.3% on-time arrivals - the worst major hub in the US. New York JFK: 73.8%. But Salt Lake City SLC: 84.6%. Minneapolis MSP: 83.9%. The on-time performance map follows fog patterns, runway capacity, and airline hub concentration. Delays cascade across the entire system.",type:"MAP",geo:"us_national",fmt:"Dot map",tbl:"BTS ATOP on-time airline performance data 2024 (public monthly)",section:"Transportation",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)"],vars:["passengers_enplaned","avg_commute_time"],join:["median_household_income","population_pct_change","housing_cpi"],sc:{emotional:6,relatability:8,surprise:6,tension:3,visual:7,data_ready:9,originality:5},vs:62,tags:"airport on-time performance hub 2024 SFO 71.3% worst JFK 73.8% Salt Lake 84.6% Minneapolis 83.9% fog runway capacity hub concentration cascade BTS ATOP"}',
',{id:"xref_water_utility_age_vs_main_breaks",title:"Water main age vs. break rate by city - the $625 billion pipe replacement problem",sub:"The average US water main is 45 years old. Cities with pipes averaging 60+ years have 2.3x the main break rate of cities under 30 years average. ASCE estimates $625 billion needed for water infrastructure replacement over 20 years. Every day, 6 billion gallons are lost to leaky pipes.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"ASCE infrastructure report card data + EPA Water Infrastructure surveys (public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["pct_bridges_poor","rural_population_pct"],join:["state_local_debt_per_capita","median_household_income","population_pct_change"],sc:{emotional:7,relatability:6,surprise:7,tension:6,visual:5,data_ready:7,originality:6},vs:62,tags:"water main age break rate city 45 years average 60+ 2.3x breaks $625 billion replacement 6 billion gallons daily lost leaky pipes ASCE EPA Water Infrastructure"}',
',{id:"county_hospital_bed_capacity_map",title:"Hospital beds per 1,000 residents by county - the capacity geography that COVID revealed",sub:"Loving County TX: 0 hospital beds. Petroleum County MT: 0. Rural frontier counties covering 12% of US land area have no hospital bed capacity. The COVID pandemic revealed that the US hospital bed system had been hollowing out for 30 years - from 4.5 beds per 1,000 in 1980 to 2.3 in 2023.",type:"MAP",geo:"us_county",fmt:"County choropleth",tbl:"CMS hospital compare + AHA hospital survey data (public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)","CDC WONDER: mortality + disease rates by county/state (wonder.cdc.gov - free)"],vars:["per_capita_health_spending","rural_population_pct"],join:["median_household_income","pct_on_medicaid","uninsured_rate"],sc:{emotional:8,relatability:7,surprise:7,tension:6,visual:8,data_ready:8,originality:5},vs:73,tags:"hospital beds per 1000 county Loving TX 0 rural frontier 12% land COVID hollowing 30 years 4.5 1980 2.3 2023 CMS hospital compare AHA survey capacity"}',
',{id:"xref_federal_highway_condition_vs_state_gdp",title:"Interstate highway pavement condition vs. state GDP per capita - do rich states have better roads?",sub:"Rhode Island: 58% of interstate miles in poor/mediocre condition - worst in the nation despite $68K GDP per capita. New Mexico: 61% poor/mediocre with $46K GDP. Meanwhile North Dakota: 8% poor with $72K GDP. Road quality is weakly correlated with state wealth (r=0.28) - more closely tied to winter climate severity and age of road network.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"FHWA Highway Statistics pavement condition + BEA state GDP per capita (both public)",section:"Transportation",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["pct_bridges_poor","state_local_debt_per_capita"],join:["median_household_income","rep_pct","rural_population_pct"],sc:{emotional:6,relatability:7,surprise:7,tension:3,visual:5,data_ready:9,originality:6},vs:61,tags:"interstate highway pavement condition state GDP Rhode Island 58% worst RI $68K New Mexico 61% North Dakota 8% climate age r=0.28 FHWA Highway Statistics BEA"}',
',{id:"us_electric_grid_transmission_bottlenecks",title:"Power grid transmission bottlenecks by region - why renewables can\'t get where they\'re needed",sub:"The US has 2,000+ GW of solar and wind power in grid interconnection queues waiting for transmission access. 95% will never be built because there is no transmission to carry it. The grid bottleneck map shows exactly where renewable energy is stuck: MISO Midwest, WECC Mountain West, and SPP Great Plains.",type:"MAP",geo:"us_national",fmt:"Special map",tbl:"LBNL Queued Up report 2024 + FERC interconnection data (both public)",section:"Energy",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","EIA State Energy Data System: production + consumption by state (eia.gov - free API)"],vars:["renewable_energy_share","energy_consumption_per_capita"],join:["oil_gas_extraction_index","coal_consumption","state_gdp_per_capita"],sc:{emotional:7,relatability:5,surprise:9,tension:7,visual:9,data_ready:7,originality:8},vs:73,tags:"power grid transmission bottlenecks 2000+ GW solar wind queue 95% never built MISO WECC SPP renewable stuck LBNL Queued Up FERC interconnection 2024"}',
',{id:"xref_municipal_bond_rating_vs_services",title:"Municipal bond rating vs. public service quality by city - the fiscal spiral that shrinks cities",sub:"Cities with below-investment-grade bond ratings spend 31% more on debt service per resident than investment-grade cities, leaving less for services. Detroit pre-bankruptcy: 44 cents of every dollar went to debt. The fiscal death spiral - poor rating, higher borrowing cost, less services, more residents leave, worse rating - is geographically concentrated.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"Moody\'s/S&P municipal bond ratings + Census government finance data (public)",section:"State Government",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["state_local_debt_per_capita","state_local_revenue_per_capita"],join:["population_pct_change","median_household_income","pct_on_snap"],sc:{emotional:8,relatability:5,surprise:8,tension:7,visual:4,data_ready:6,originality:7},vs:68,tags:"municipal bond rating public service city below investment-grade 31% more debt service Detroit 44 cents dollar fiscal death spiral higher cost fewer services residents leave Moody S&P Census"}',
',{id:"us_wildfire_risk_by_county_map",title:"Wildfire risk index by county 2024 - the expanding danger zone",sub:"Trinity County CA: the highest wildfire risk county in the US (FSC risk score 99/100). 44 million homes are now in the wildland-urban interface (WUI) - a 40% increase since 2000. The wildfire risk map has expanded dramatically eastward from the traditional Western zone since 2010.",type:"MAP",geo:"us_county",fmt:"County choropleth",tbl:"USFS Wildfire Risk to Communities dataset (public) + First Street Foundation risk index",section:"Geography",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)"],vars:["pct_forest","national_forest_acres"],join:["median_household_income","housing_permits_total","rural_population_pct"],sc:{emotional:8,relatability:6,surprise:7,tension:7,visual:9,data_ready:8,originality:5},vs:73,tags:"wildfire risk county 2024 Trinity CA 99/100 44 million homes WUI 40% increase 2000 expanded eastward Western zone 2010 USFS First Street Foundation wildland-urban interface"}',
',{id:"xref_homeowners_insurance_withdrawal_map",title:"Homeowners insurance availability by state 2024 - where coverage is disappearing",sub:"California: State Farm, Allstate, Farmers, and USAA have all stopped writing new policies in 2023-2024. Florida: Citizens Insurance (state insurer of last resort) now covers 1.4 million homes - double 2020. The private insurance withdrawal map is a leading indicator of where the housing market will fail next.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"NAIC insurance market data + state DOI reports 2024 (public)",section:"Housing",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["home_price_index_2024","flood_zone_uninsured_pct"],join:["median_household_income","housing_permits_total","coastal_flood_exposure"],sc:{emotional:9,relatability:7,surprise:9,tension:8,visual:7,data_ready:7,originality:8},vs:80,tags:"homeowners insurance availability state 2024 California State Farm Allstate Farmers USAA stopped new policies Florida Citizens 1.4 million double 2020 withdrawal leading indicator housing market NAIC DOI"}',
',{id:"xref_flood_zone_vs_uninsured_rate",title:"FEMA flood zone designation vs. flood insurance coverage rate by county - the protection gap",sub:"In FEMA 100-year flood zones: only 27% of homes have flood insurance. In coastal Louisiana: 31%. In inland Midwest flood zones: 14%. The national flood insurance protection gap means that when the next major flood event hits, the vast majority of property losses will be uninsured - falling on individuals and federal disaster relief.",type:"XREF",geo:"us_county",fmt:"County choropleth",tbl:"FEMA National Flood Insurance Program policies + FEMA flood zone FIRM data (both public)",section:"Housing",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["flood_zone_uninsured_pct","coastline_miles"],join:["median_household_income","home_price_index_2024","rural_population_pct"],sc:{emotional:8,relatability:6,surprise:8,tension:7,visual:7,data_ready:8,originality:6},vs:73,tags:"flood zone FEMA insurance coverage county 100-year 27% homes Louisiana 31% Midwest 14% protection gap uninsured losses individuals federal disaster NFIP FIRM policies"}',
',{id:"county_pharmacy_desert_map",title:"Pharmacy deserts by county - where prescription access ends",sub:"308 US counties have no pharmacy within 15 miles of a significant share of residents. The pharmacy desert geography concentrates in rural Appalachia, the Great Plains, and the Mississippi Delta - precisely the counties with the highest rates of chronic disease requiring regular prescriptions.",type:"MAP",geo:"us_county",fmt:"County choropleth",tbl:"HRSA pharmacy access data + GoodRx pharmacy density analysis (public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by county (bls.gov - free)","CDC WONDER: mortality + disease rates by county/state (wonder.cdc.gov - free)"],vars:["per_capita_health_spending","rural_population_pct"],join:["pct_on_medicaid","median_household_income","uninsured_rate"],sc:{emotional:8,relatability:7,surprise:7,tension:6,visual:7,data_ready:7,originality:7},vs:71,tags:"pharmacy desert county 308 15 miles rural Appalachia Great Plains Mississippi Delta chronic disease prescriptions HRSA GoodRx density access"}',
',{id:"xref_internet_speeds_vs_home_value",title:"Broadband speed vs. home value appreciation by zip code - fiber as a property value driver",sub:"Zip codes receiving gigabit fiber service from 2015-2020 showed 7.1% higher home value appreciation over the following 5 years than comparable unserved zips. The effect is largest in mid-sized cities and suburban areas. Fiber internet is now a property value variable like school quality.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"FCC broadband deployment data + Zillow/FHFA home price index by zip code (public)",section:"Information",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["broadband_access_pct","home_price_index_2024"],join:["median_household_income","housing_permits_total","pct_bachelors"],sc:{emotional:7,relatability:7,surprise:7,tension:4,visual:5,data_ready:7,originality:7},vs:63,tags:"broadband speed home value zip gigabit fiber 2015 2020 7.1% appreciation 5 years mid-sized cities suburban school quality property value driver FCC Zillow FHFA"}',
',{id:"us_grid_battery_storage_by_state",title:"Grid-scale battery storage installed by state 2024 - the energy transition infrastructure map",sub:"California: 8,700 MW grid-scale battery installed - 54% of all US capacity. Texas: 3,200 MW. The battery storage map is the renewable integration map - states with the most storage can absorb the most intermittent wind and solar. Without storage, renewable penetration hits a hard ceiling around 40%.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"EIA battery storage capacity by state 2024 (public monthly update)",section:"Energy",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","EIA State Energy Data System: production + consumption by state (eia.gov - free API)"],vars:["renewable_energy_share","energy_consumption_per_capita"],join:["oil_gas_extraction_index","coal_consumption","state_gdp_per_capita"],sc:{emotional:6,relatability:5,surprise:7,tension:5,visual:7,data_ready:9,originality:6},vs:61,tags:"grid-scale battery storage state 2024 California 8700 MW 54% Texas 3200 MW renewable integration intermittent wind solar ceiling 40% EIA battery capacity monthly"}'
